// Java 25 exam prep - NIO.2 file IO
// Learn: read and write whole files with Path and Files.
// Path names the file; Files performs the IO.
Path notes = Path.of("notes.txt");
Files.writeString(notes, "line one\nline two\n");
String body = Files.readString(notes);
long lineCount = body.lines().count();
System.out.println(lineCount + " lines, exists=" + Files.exists(notes));
